package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            @Override
            public int read() throws IOException {
                return super.read();
            }
        };
    }

    @Test
    void testRead_returnsCharNotNewline_updatesLastCharAndLineCounter() throws IOException {
        // Spy on extendedBufferedReader to mock super.read()
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        // Mock the underlying Reader to return 'A' on read
        doReturn((int) 'A').when(spyReader).readSuper();

        // Call the real read method on spy
        int result = spyReader.read();
        assertEquals('A', result);

        int lastChar = getPrivateIntField(spyReader, "lastChar");
        int lineCounter = getPrivateIntField(spyReader, "lineCounter");
        assertEquals('A', lastChar);
        assertEquals(0, lineCounter);
    }

    @Test
    void testRead_returnsNewline_incrementsLineCounterAndUpdatesLastChar() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn((int) '\n').when(spyReader).readSuper();
        int result = spyReader.read();
        assertEquals('\n', result);
        int lastChar = getPrivateIntField(spyReader, "lastChar");
        int lineCounter = getPrivateIntField(spyReader, "lineCounter");
        assertEquals('\n', lastChar);
        assertEquals(1, lineCounter);
    }

    @Test
    void testRead_returnsEndOfStream_updatesLastCharNoIncrementLineCounter() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(ExtendedBufferedReader.END_OF_STREAM).when(spyReader).readSuper();
        int result = spyReader.read();
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, result);
        int lastChar = getPrivateIntField(spyReader, "lastChar");
        int lineCounter = getPrivateIntField(spyReader, "lineCounter");
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);
        assertEquals(0, lineCounter);
    }

    private int getPrivateIntField(Object instance, String fieldName) {
        try {
            Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.getInt(instance);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
```

**Note:**  
To make the tests work correctly, you need to add a helper method `readSuper()` in `ExtendedBufferedReader` that calls `super.read()`. Since you cannot mock calls to `super.read()` directly, you can add this method to the class under test:

```java
// In ExtendedBufferedReader.java
public int readSuper() throws IOException {
    return super.read();
}
```

This allows you to mock `readSuper()` in the tests instead of `read()`.
